// Auto-generated from partnummer_manuren_repair_overhaul_v3_brakes_hoger.csv

export type ComponentType = "Wheel" | "Brake" | "Battery";

export interface PartNumberEntry {
  component_type: ComponentType;
  repair_mh?: number;
  overhaul_mh?: number;
  battery_mh?: number;
}

export function normalizePartNumber(pn: string): string {
  return pn.toLowerCase().replace(/\s+/g, "");
}

