export const PART_NUMBER_HOURS: Record<string, PartNumberEntry> = Object.fromEntries(
  Object.entries(PART_NUMBER_HOURS_RAW).map(([key, value]) => [normalizePartNumber(key), value])
);

export function getTotalHoursForPart(
  workOrderType: string,
  partNumber: string | null | undefined,
): number {
  const fallback = FALLBACK_HOURS[workOrderType] ?? 0;
  if (!partNumber) return fallback;

  const entry = PART_NUMBER_HOURS[normalizePartNumber(partNumber)];
  if (!entry) return fallback;

  if (workOrderType === "Battery") return entry.battery_mh ?? fallback;
  if (workOrderType.includes("Repair")) return entry.repair_mh ?? fallback;
  if (workOrderType.includes("Overhaul")) return entry.overhaul_mh ?? fallback;

  return fallback;
}